function setupCustomPlayer(video) {
  // 手势滑动快进
  let isDragging = false;
  let startX = 0;
  let startTime = 0;

  // 长按加速相关变量
  let longPressTimer = null;
  const LONG_PRESS_DELAY = 300;
  const NORMAL_SPEED = 1.25;
  const FAST_SPEED = 3;
  let wasPaused = false;

  // 触摸事件处理
  function handleTouchStart(e) {
    startX = e.touches[0].clientX;
    startTime = video.currentTime;
    wasPaused = video.paused;

    longPressTimer = setTimeout(() => {
      video.playbackRate = FAST_SPEED;
      if (wasPaused) video.play();
    }, LONG_PRESS_DELAY);
  }

  function handleTouchMove(e) {
    if (longPressTimer) {
      clearTimeout(longPressTimer);
      longPressTimer = null;
    }

    const dx = e.touches[0].clientX - startX;
    if (Math.abs(dx) > 10) {
      if (!isDragging) {
        video.pause();
        isDragging = true;
      }
      const change = (dx / video.clientWidth) * video.duration;
      video.currentTime = Math.max(0, Math.min(startTime + change, video.duration));
    }
  }

  function handleTouchEnd() {
    if (longPressTimer) {
      clearTimeout(longPressTimer);
      longPressTimer = null;
    }

    if (isDragging) {
      video.playbackRate = NORMAL_SPEED;
      video.play();
      isDragging = false;
    } else if (video.playbackRate === FAST_SPEED) {
      video.playbackRate = NORMAL_SPEED;
      if (wasPaused) video.pause();
    }
  }

  // 添加触摸事件监听
  video.addEventListener('touchstart', handleTouchStart);
  video.addEventListener('touchmove', handleTouchMove);
  video.addEventListener('touchend', handleTouchEnd);

  // 初始播放速度
  video.playbackRate = NORMAL_SPEED;

  // 创建按钮的通用函数
  function createButton(text, onClick, position, width = '20px') {
    const button = document.createElement('button');
    button.textContent = text;
    button.style.position = 'absolute';
